b:if.b:template-skin:

body#layout {
background-color: #fff4e5;
border: 1px solid #f7dab2;
font-family: Arial, sans-serif;
font-size: 12px;
width: 780px;
margin: 20px auto;
padding: 80px 36px 25px;
position: relative
}

body#layout::before {
    content: "linkmagz versi 3.8.0 (29/11/2025)";
    display: block;
    position: absolute;
    left: 36px;
    font-family: Arial, sans-serif;
    background: #f9e8d5;
    padding: 10px 14px;
    color: #795e41;
    top: 19px
}

body#layout .add_widget a,
body#layout div.layout-title,
body#layout div.layout-widget-description {
    font-size: 1em;
    overflow: hidden
}

body#layout .add_widget {
    border: 1px dashed #757575;
    padding: 12px;
    position: relative;
    text-align: left;
    margin-bottom: 8px
}

body#layout .add_widget a {
    font-weight: 700;
    text-transform: uppercase;
    font-size: 12px
}

body#layout div.section {
    background: 0 0;
    margin: 0 0 10px;
    padding: 0;
    border: none;
    font-family: Arial, sans-serif
}

body#layout div.section h4 {
    background: #b28850;
    color: #fff;
    text-transform: capitalize;
    font-weight: 400;
    padding: 3px 10px;
    font-size: 1em;
    line-height: 18px;
    margin: 0 0 8px;
    text-align: center
}

body#layout div.section>div {
    margin-top: 0
}

body#layout div.layout-widget-description {
    font-size: 12px;
    opacity: .7;
    display: none
}

body#layout .editlink.icon {
    top: 12px
}

body#layout div.widget .widget-content {
    padding: 12px
}

body#layout #main-content {
    margin-bottom: 10px
}

body#layout #main-content .Blog .widget-content {
    height: 120px
}

body#layout #above-post-widget h4,
body#layout #bellow-header-widget h4,
body#layout #bellow-header-widget2 h4,
body#layout #custom-css h4,
body#layout #custom-javascript-footer h4,
body#layout #footer-text h4,
body#layout #footer-widget-html h4,
body#layout #header h4,
body#layout #iklan-atas h4,
body#layout #iklan-bawah h4,
body#layout #iklan-infeed h4,
body#layout #iklan-tengah1 h4,
body#layout #iklan-tengah2 h4,
body#layout #main-content h4,
body#layout #matched-content h4,
body#layout #navbarrr h4,
body#layout #navmenu h4,
body#layout #page-navmenu h4,
body#layout #template-settings h4,
body#layout #top-widget h4,
body#layout #top-widget2 h4 {
    display: none
}

body#layout .custom-css,
body#layout .custom-javascript-footer,
body#layout .template-settings {
    width: 300px;
    display: block
}

body#layout .custom-css div.widget .widget-content,
body#layout .custom-javascript-footer div.widget .widget-content,
body#layout .template-settings div.widget .widget-content {
    padding: 6px 12px;
    background: #e4ffff
}

body#layout .custom-css h4,
body#layout .custom-javascript-footer h4,
body#layout .template-settings h4 {
    background: #569494;
    display: none
}

body#layout .custom-css div.layout-widget-description,
body#layout .custom-javascript-footer div.layout-widget-description,
body#layout .template-settings div.layout-widget-description {
    display: none
}

body#layout .custom-css .editlink.icon,
body#layout .custom-javascript-footer .editlink.icon,
body#layout .template-settings .editlink.icon {
    top: 6px
}

body#layout #template-settings div.widget {
    margin-top: 0
}

body#layout #iklan-atas div.widget .widget-content,
body#layout #iklan-bawah div.widget .widget-content,
body#layout #iklan-tengah1 div.widget .widget-content,
body#layout #iklan-tengah2 div.widget .widget-content {
    background: #eaffe9;
    padding: 6px 12px
}

body#layout #iklan-atas div.widget .widget-content .editlink.icon,
body#layout #iklan-bawah div.widget .widget-content .editlink.icon,
body#layout #iklan-tengah1 div.widget .widget-content .editlink.icon,
body#layout #iklan-tengah2 div.widget .widget-content .editlink.icon {
    top: 5px
}

body#layout #matched-content div.widget .widget-content {
    background: #ffe9e9;
    padding: 6px 12px
}

body#layout #matched-content div.widget .widget-content .editlink.icon {
    top: 5px
}

body#layout #iklan-infeed div.widget .widget-content {
    background: #e9e9ff;
    padding: 6px 12px
}

body#layout #iklan-infeed div.widget .widget-content .editlink.icon {
    top: 5px
}

body#layout #header-outer {
    padding-top: 20px
}

body#layout #header {
    float: left;
    width: 48%
}

body#layout #wrapper {
    padding: 20px 0
}

body#layout #header-content::after,
body#layout #wrapper::after {
    content: "";
    clear: both;
    display: block
}

body#layout #content-wrap {
    width: 58%;
    float: left
}

body#layout #sidebar-wrap {
    width: 38%;
    float: right
}

body#layout #sidebar-wrap .sidebar-sticky {
    padding-top: 10px
}

body#layout #footer-outer {
    padding-bottom: 20px
}
